[Serializable]
public class Permission
{
    public string Name { get; set; }
    public string Resource { get; set; }
    public List<string> Actions { get; set; }

    public Permission()
    {
        Actions = new List<string>();
    }

    public Permission(string name, string resource, params string[] actions)
    {
        Name = name;
        Resource = resource;
        Actions = new List<string>(actions);
    }

    public bool HasAction(string action)
    {
        return Actions != null && Actions.Contains(action);
    }

    public bool CanAccess(string resource, string action)
    {
        return string.Equals(Resource, resource, StringComparison.OrdinalIgnoreCase) && HasAction(action);
    }

    public void GrantAction(string action)
    {
        if (Actions == null)
            Actions = new List<string>();
        if (!Actions.Contains(action))
            Actions.Add(action);
    }

    public void RevokeAction(string action)
    {
        Actions?.Remove(action);
    }

    public override string ToString()
    {
        return $"Permission[{Name}] Resource={Resource}, Actions=[{string.Join(", ", Actions ?? new List<string>())}]";
    }
}

[Serializable]
public class CartItem
{
    public string ProductId { get; set; }
    public string ProductName { get; set; }
    public decimal Price { get; set; }
