[Serializable]
public class ShoppingCart
{
    public List<CartItem> Items { get; set; }

    public ShoppingCart()
    {
        Items = new List<CartItem>();
    }

    public void AddItem(CartItem item)
    {
        var existing = Items.Find(i => i.ProductId == item.ProductId);
        if (existing != null)
        {
            existing.Quantity += item.Quantity;
        }
        else
        {
            Items.Add(item);
        }
    }

    public bool RemoveItem(string productId)
    {
        return Items.RemoveAll(i => i.ProductId == productId) > 0;
    }

    public void UpdateQuantity(string productId, int quantity)
    {
        var item = Items.Find(i => i.ProductId == productId);
        if (item != null)
        {
            if (quantity <= 0)
                RemoveItem(productId);
            else
                item.Quantity = quantity;
        }
    }

    public decimal GetCartTotal()
    {
        decimal total = 0;
        foreach (var item in Items)
            total += item.GetTotal();
        return total;
    }

    public int GetItemCount()
    {
        int count = 0;
        foreach (var item in Items)
            count += item.Quantity;
        return count;
    }

    public void Clear()
    {
        Items.Clear();
    }

    public override string ToString()
    {
        return $"ShoppingCart: {GetItemCount()} items, Total: ${GetCartTotal():F2}";
    }
}

