    public UserSession()
    {
        SessionId = Guid.NewGuid().ToString("N");
        CreatedAt = DateTime.UtcNow;
        LastAccessedAt = DateTime.UtcNow;
        ExpiresAt = DateTime.UtcNow.AddHours(24);
        Preferences = new UserPreferences();
        Cart = new ShoppingCart();
        Permissions = new List<Permission>();
        CustomData = new Dictionary<string, object>();
    }

    public UserSession(string userId, string username, string email) : this()
    {
        UserId = userId;
        Username = username;
        Email = email;
    }

    public void AddPermission(Permission permission)
    {
        if (!Permissions.Exists(p => p.Name == permission.Name && p.Resource == permission.Resource))
        {
            Permissions.Add(permission);
        }
    }

    public void RemovePermission(string permissionName)
    {
        Permissions.RemoveAll(p => p.Name == permissionName);
    }

    public bool HasPermission(string resource, string action)
    {
        return Permissions.Exists(p => p.CanAccess(resource, action));
    }

    public List<Permission> GetPermissionsForResource(string resource)
    {
        return Permissions.FindAll(p => string.Equals(p.Resource, resource, StringComparison.OrdinalIgnoreCase));
    }

    public bool IsExpired()
    {
        return DateTime.UtcNow > ExpiresAt;
    }

    public void Touch()
    {
        LastAccessedAt = DateTime.UtcNow;
    }

    public void ExtendExpiration(TimeSpan duration)
    {
        ExpiresAt = DateTime.UtcNow.Add(duration);
    }

