    {
        CustomData[key] = value;
    }

    public object GetCustomData(string key)
    {
        return CustomData.ContainsKey(key) ? CustomData[key] : null;
    }

    public override string ToString()
    {
        return $"Session[{SessionId}] User={Username}({UserId}), Expires={ExpiresAt}, " +
               $"Permissions={Permissions.Count}, Cart={Cart.GetItemCount()} items";
