}

public class SessionManager
{
    private readonly string _sessionDirectory;
    private readonly Dictionary<string, UserSession> _activeSessions;
    private readonly object _lock = new object();

    public SessionManager(string sessionDirectory = null)
    {
        _sessionDirectory = sessionDirectory ?? Path.Combine(Path.GetTempPath(), "sessions");
        _activeSessions = new Dictionary<string, UserSession>();

        if (!Directory.Exists(_sessionDirectory))
        {
            Directory.CreateDirectory(_sessionDirectory);
        }
    }

    public UserSession CreateSession(string userId, string username, string email)
    {
        var session = new UserSession(userId, username, email);
        lock (_lock)
        {
            _activeSessions[session.SessionId] = session;
        }
        SaveSession(session);
        Console.WriteLine($"[SessionManager] Created session: {session.SessionId} for user {username}");
        return session;
    }

    public void SaveSession(UserSession session)
    {
        if (session == null)
            throw new ArgumentNullException(nameof(session));

        string filePath = GetSessionFilePath(session.SessionId);

#pragma warning disable SYSLIB0011
        BinaryFormatter formatter = new BinaryFormatter();
        using (FileStream stream = new FileStream(filePath, FileMode.Create, FileAccess.Write))
        {
            formatter.Serialize(stream, session);
        }
#pragma warning restore SYSLIB0011

        Console.WriteLine($"[SessionManager] Saved session {session.SessionId} to disk");
    }

    public UserSession LoadSession(string sessionId)
    {
        if (string.IsNullOrEmpty(sessionId))
            throw new ArgumentNullException(nameof(sessionId));

        lock (_lock)
        {
            if (_activeSessions.ContainsKey(sessionId))
            {
                var cached = _activeSessions[sessionId];
                if (!cached.IsExpired())
                {
                    cached.Touch();
                    return cached;
                }
                else
                {
                    _activeSessions.Remove(sessionId);
                    DeleteSessionFile(sessionId);
                    Console.WriteLine($"[SessionManager] Session {sessionId} expired (cached)");
                    return null;
                }
            }
        }

        string filePath = GetSessionFilePath(sessionId);
        if (!File.Exists(filePath))
        {
            Console.WriteLine($"[SessionManager] Session file not found: {sessionId}");
            return null;
        }

#pragma warning disable SYSLIB0011
        BinaryFormatter formatter = new BinaryFormatter();
        UserSession session;
        using (FileStream stream = new FileStream(filePath, FileMode.Open, FileAccess.Read))
        {
            session = (UserSession)formatter.Deserialize(stream);
        }
#pragma warning restore SYSLIB0011

        if (session.IsExpired())
        {
            DeleteSessionFile(sessionId);
            Console.WriteLine($"[SessionManager] Session {sessionId} expired (disk)");
            return null;
        }

        session.Touch();
        lock (_lock)
        {
            _activeSessions[sessionId] = session;
        }

        Console.WriteLine($"[SessionManager] Loaded session {sessionId} from disk");
        return session;
    }

    public void UpdateSession(UserSession session)
    {
        if (session == null)
            throw new ArgumentNullException(nameof(session));

        session.Touch();
        lock (_lock)
        {
            _activeSessions[session.SessionId] = session;
        }
        SaveSession(session);
        Console.WriteLine($"[SessionManager] Updated session {session.SessionId}");
    }

    public bool DestroySession(string sessionId)
    {
        lock (_lock)
        {
            _activeSessions.Remove(sessionId);
        }
        bool fileDeleted = DeleteSessionFile(sessionId);
        Console.WriteLine($"[SessionManager] Destroyed session {sessionId}");
        return fileDeleted;
    }

    public void CleanExpiredSessions()
    {
        int cleaned = 0;

        lock (_lock)
        {
            var expiredKeys = new List<string>();
            foreach (var kvp in _activeSessions)
            {
                if (kvp.Value.IsExpired())
                    expiredKeys.Add(kvp.Key);
            }
            foreach (var key in expiredKeys)
            {
                _activeSessions.Remove(key);
                DeleteSessionFile(key);
                cleaned++;
            }
        }

        // Also check files on disk
        if (Directory.Exists(_sessionDirectory))
        {
            foreach (string file in Directory.GetFiles(_sessionDirectory, "*.session"))
            {
                try
                {
#pragma warning disable SYSLIB0011
                    BinaryFormatter formatter = new BinaryFormatter();
                    using (FileStream stream = new FileStream(file, FileMode.Open, FileAccess.Read))
                    {
                        var session = (UserSession)formatter.Deserialize(stream);
                        if (session.IsExpired())
                        {
                            stream.Close();
                            File.Delete(file);
                            cleaned++;
                        }
                    }
#pragma warning restore SYSLIB0011
                }
                catch (Exception ex)
                {
                    Console.WriteLine($"[SessionManager] Error cleaning session file {file}: {ex.Message}");
                    try { File.Delete(file); } catch { }
                }
            }
        }

        Console.WriteLine($"[SessionManager] Cleaned {cleaned} expired sessions");
    }

    public List<UserSession> GetAllActiveSessions()
    {
        var sessions = new List<UserSession>();

        if (Directory.Exists(_sessionDirectory))
        {
            foreach (string file in Directory.GetFiles(_sessionDirectory, "*.session"))
            {
                try
                {
#pragma warning disable SYSLIB0011
                    BinaryFormatter formatter = new BinaryFormatter();
                    using (FileStream stream = new FileStream(file, FileMode.Open, FileAccess.Read))
                    {
                        var session = (UserSession)formatter.Deserialize(stream);
                        if (!session.IsExpired())
                            sessions.Add(session);
                    }
#pragma warning restore SYSLIB0011
                }
                catch (Exception ex)
                {
                    Console.WriteLine($"[SessionManager] Error reading session file {file}: {ex.Message}");
                }
            }
        }

        return sessions;
    }

    public int GetActiveSessionCount()
    {
        lock (_lock)
        {
            int count = 0;
            foreach (var kvp in _activeSessions)
            {
                if (!kvp.Value.IsExpired())
                    count++;
            }
            return count;
        }
    }

    private string GetSessionFilePath(string sessionId)
    {
        return Path.Combine(_sessionDirectory, $"{sessionId}.session");
    }

    private bool DeleteSessionFile(string sessionId)
    {
        string filePath = GetSessionFilePath(sessionId);
        if (File.Exists(filePath))
        {
            File.Delete(filePath);
            return true;
        }
        return false;
    }
