class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("=== Session Management System Demo ===\n");

        string sessionDir = Path.Combine(Path.GetTempPath(), "demo_sessions_" + Guid.NewGuid().ToString("N").Substring(0, 8));
        var sessionManager = new SessionManager(sessionDir);

        try
        {
            // Create a session
            Console.WriteLine("--- Creating Session ---");
            var session = sessionManager.CreateSession("user-001", "john_doe", "john@example.com");
            Console.WriteLine($"Created: {session}\n");

            // Set preferences
            Console.WriteLine("--- Setting Preferences ---");
            session.Preferences.Theme = "dark";
            session.Preferences.Language = "en-US";
            session.Preferences.Currency = "EUR";
            session.Preferences.ItemsPerPage = 50;
            session.Preferences.SetCustomSetting("sidebar_collapsed", "true");
            session.Preferences.SetCustomSetting("font_size", "14");
            Console.WriteLine($"Preferences: {session.Preferences}");
            Console.WriteLine($"Custom setting 'font_size': {session.Preferences.GetCustomSetting("font_size")}\n");

            // Add items to cart
            Console.WriteLine("--- Shopping Cart ---");
            session.Cart.AddItem(new CartItem("PROD-001", "Wireless Mouse", 29.99m, 1));
            session.Cart.AddItem(new CartItem("PROD-002", "Mechanical Keyboard", 89.99m, 1));
            session.Cart.AddItem(new CartItem("PROD-003", "USB-C Hub", 45.50m, 2));
            session.Cart.AddItem(new CartItem("PROD-001", "Wireless Mouse", 29.99m, 1)); // Add another mouse
            Console.WriteLine($"Cart: {session.Cart}");
            foreach (var item in session.Cart.Items)
                Console.WriteLine($"  - {item}");
            Console.WriteLine();

            // Add permissions
            Console.WriteLine("--- Permissions ---");
            session.AddPermission(new Permission("admin_users", "users", "read", "write", "delete"));
            session.AddPermission(new Permission("view_reports", "reports", "read"));
            session.AddPermission(new Permission("manage_products", "products", "read", "write", "create"));
            session.AddPermission(new Permission("view_orders", "orders", "read"));

            foreach (var perm in session.Permissions)
                Console.WriteLine($"  {perm}");

            Console.WriteLine($"\n  Can read users? {session.HasPermission("users", "read")}");
            Console.WriteLine($"  Can delete reports? {session.HasPermission("reports", "delete")}");
            Console.WriteLine($"  Can write products? {session.HasPermission("products", "write")}");

            // Grant a new action to an existing permission
            var reportPerm = session.Permissions.Find(p => p.Name == "view_reports");
            reportPerm?.GrantAction("export");
            Console.WriteLine($"  After granting 'export' to reports: {reportPerm}");
            Console.WriteLine();

            // Add custom data
            session.SetCustomData("last_search", "mechanical keyboard");
            session.SetCustomData("login_ip", "192.168.1.100");

            // Save session to disk
            Console.WriteLine("--- Saving Session to Disk ---");
            sessionManager.UpdateSession(session);
            string sessionId = session.SessionId;
            Console.WriteLine($"Session saved: {sessionId}\n");

            // Load session from disk (simulate new request)
            Console.WriteLine("--- Loading Session from Disk ---");
            var loadedSession = sessionManager.LoadSession(sessionId);
            if (loadedSession != null)
            {
                Console.WriteLine($"Loaded: {loadedSession}");
                Console.WriteLine($"  User: {loadedSession.Username} ({loadedSession.Email})");
                Console.WriteLine($"  Preferences: {loadedSession.Preferences}");
                Console.WriteLine($"  Cart: {loadedSession.Cart}");
                Console.WriteLine($"  Permissions count: {loadedSession.Permissions.Count}");
                Console.WriteLine($"  Can read users? {loadedSession.HasPermission("users", "read")}");
                Console.WriteLine($"  Can export reports? {loadedSession.HasPermission("reports", "export")}");
                Console.WriteLine($"  Last search: {loadedSession.GetCustomData("last_search")}");
                Console.WriteLine($"  Login IP: {loadedSession.GetCustomData("login_ip")}");

                // Verify cart items survived serialization
                Console.WriteLine("\n  Cart items after deserialization:");
                foreach (var item in loadedSession.Cart.Items)
                    Console.WriteLine($"    - {item}");
                Console.WriteLine($"  Cart total: ${loadedSession.Cart.GetCartTotal():F2}");
            }
            Console.WriteLine();

            // Create additional sessions
            Console.WriteLine("--- Creating Additional Sessions ---");
            var session2 = sessionManager.CreateSession("user-002", "jane_smith", "jane@example.com");
            session2.Cart.AddItem(new CartItem("PROD-005", "Monitor Stand", 35.00m, 1));
            session2.AddPermission(new Permission("basic_access", "dashboard", "read"));
            sessionManager.UpdateSession(session2);

            var session3 = sessionManager.CreateSession("user-003", "bob_wilson", "bob@example.com");
            session3.Preferences.Theme = "solarized";
            session3.AddPermission(new Permission("viewer", "reports", "read"));
            sessionManager.UpdateSession(session3);

            Console.WriteLine($"Active sessions in memory: {sessionManager.GetActiveSessionCount()}");

            var allSessions = sessionManager.GetAllActiveSessions();
            Console.WriteLine($"Active sessions on disk: {allSessions.Count}");
            foreach (var s in allSessions)
                Console.WriteLine($"  - {s}");
            Console.WriteLine();

            // Modify cart and re-save
            Console.WriteLine("--- Modifying Cart ---");
            loadedSession.Cart.UpdateQuantity("PROD-002", 3);
            loadedSession.Cart.RemoveItem("PROD-003");
            loadedSession.Cart.AddItem(new CartItem("PROD-010", "Webcam HD", 59.99m, 1));
            sessionManager.UpdateSession(loadedSession);

            var reloaded = sessionManager.LoadSession(sessionId);
            Console.WriteLine($"Updated cart: {reloaded.Cart}");
            foreach (var item in reloaded.Cart.Items)
                Console.WriteLine($"  - {item}");
            Console.WriteLine();

            // Revoke permission and verify
            Console.WriteLine("--- Revoking Permission ---");
            var adminPerm = reloaded.Permissions.Find(p => p.Name == "admin_users");
            adminPerm?.RevokeAction("delete");
            Console.WriteLine($"After revoking 'delete' from admin_users: {adminPerm}");
            Console.WriteLine($"  Can delete users? {reloaded.HasPermission("users", "delete")}");
            Console.WriteLine($"  Can read users? {reloaded.HasPermission("users", "read")}");
            sessionManager.UpdateSession(reloaded);
            Console.WriteLine();

            // Destroy a session
            Console.WriteLine("--- Destroying Session ---");
            sessionManager.DestroySession(session2.SessionId);
            var destroyed = sessionManager.LoadSession(session2.SessionId);
            Console.WriteLine($"Session2 after destroy: {(destroyed == null ? "null (correctly destroyed)" : "still exists!")}\n");

            // Clean expired sessions
            Console.WriteLine("--- Cleaning Expired Sessions ---");
            sessionManager.CleanExpiredSessions();

            Console.WriteLine($"\nFinal active sessions on disk: {sessionManager.GetAllActiveSessions().Count}");

            // Demonstrate session expiration check
            Console.WriteLine("\n--- Session Expiration ---");
            Console.WriteLine($"Session expired? {reloaded.IsExpired()}");
            Console.WriteLine($"Expires at: {reloaded.ExpiresAt}");
            reloaded.ExtendExpiration(TimeSpan.FromDays(7));
            Console.WriteLine($"After extension, expires at: {reloaded.ExpiresAt}");
        }
        finally
        {
            // Cleanup
            try
            {
                if (Directory.Exists(sessionDir))
                    Directory.Delete(sessionDir, true);
                Console.WriteLine($"\nCleaned up session directory: {sessionDir}");
            }
            catch { }
        }

        Console.WriteLine("\n=== Demo Complete ===");
    }
}